  name: "John",
  age: 30,
  city: "New York"
};

console.log(myObj.name); // 输出 "John"
console.log(myObj["age"]); // 输出 30
```

在以上示例中，使用点（.）属性访问器来访问对象中的 name 属性值，并且使用方括号（[]）属性访问器来访问对象中的 age 属性值。输出结果将是：

```
